'use strict';
/**
 * AGENT 8 — Approval Gate Agent (MANDATORY)
 *
 * Reviews every fix generated by Agent 7 and decides:
 *   APPROVED       — fix is correct, safe, and ready for human to apply in staging
 *   REJECTED       — fix is incorrect, unsafe, or would cause data loss
 *   NEEDS_REVISION — fix addresses the right problem but needs amendments
 *
 * Evaluation criteria:
 *   1. Correctness     — Does the fix actually solve the root cause?
 *   2. Safety          — Could it cause data loss, outage, or security regression?
 *   3. Side effects    — What else might this change affect?
 *   4. Supabase integrity — Does it respect FK constraints, RLS, and schema?
 *   5. Deployment order — Does it have prerequisites?
 *
 * THIS AGENT DOES NOT APPLY ANY FIXES.
 * Returns: { agent, status, decisions, summary }
 */

const logger = require('../utils/logger');

// ── Evaluation rules ───────────────────────────────────────────────────────────
// Each rule is a function(fix) → { pass: bool, reason: string }
const SAFETY_RULES = [

  // Rule 1: SQL that drops or truncates data must be rejected
  (fix) => {
    const code = (fix.code || '').toLowerCase();
    const danger = ['drop table', 'truncate table', 'delete from', 'drop database'];
    const found  = danger.filter(d => code.includes(d));
    if (found.length > 0) {
      return { pass: false, reason: `REJECTED: Fix contains dangerous SQL operations: ${found.join(', ')}. These may cause data loss.` };
    }
    return { pass: true };
  },

  // Rule 2: CREATE POLICY must specify role explicitly
  (fix) => {
    if (fix.type !== 'sql') return { pass: true };
    const code = (fix.code || '').toLowerCase();
    if (code.includes('create policy') && !code.includes('to authenticated') && !code.includes('to anon') && !code.includes('to public')) {
      return {
        pass: false,
        reason: 'NEEDS_REVISION: CREATE POLICY statement is missing explicit role clause (TO authenticated / TO anon). Without this, the policy may apply to the wrong role.',
      };
    }
    return { pass: true };
  },

  // Rule 3: ALTER COLUMN TYPE on a large table needs downtime warning
  (fix) => {
    const code = (fix.code || '').toLowerCase();
    if (code.includes('alter column') && code.includes('type')) {
      return {
        pass: null,  // null = needs revision (not outright rejected)
        reason: 'NEEDS_REVISION: ALTER COLUMN TYPE locks the table. For tables with many rows, this may cause downtime. Schedule during low-traffic. Ensure backup exists. Consider a staged migration with a new column.',
      };
    }
    return { pass: true };
  },

  // Rule 4: JavaScript fixes touching auth flow need regression test
  (fix) => {
    if (fix.type !== 'javascript') return { pass: true };
    const authFiles = ['auth.js', 'supabase.js'];
    if (authFiles.some(f => (fix.file || '').includes(f))) {
      return {
        pass: null,
        reason: 'NEEDS_REVISION: This fix modifies authentication code. Must be tested against all auth flows: email login, signup, OTP, OAuth, 2FA, password reset. Add manual test checklist before applying.',
      };
    }
    return { pass: true };
  },

  // Rule 5: Fixes marked 'dangerous' are auto-escalated
  (fix) => {
    if (fix.safetyLevel === 'dangerous') {
      return {
        pass: false,
        reason: 'REJECTED: This fix is classified as DANGEROUS and requires DBA/engineering lead review before proceeding. It involves breaking changes that require data migration. Do not apply without a coordinated rollout plan.',
      };
    }
    return { pass: true };
  },

  // Rule 6: RLS policies must not use USING(true) on sensitive tables
  (fix) => {
    if (fix.type !== 'sql') return { pass: true };
    const code  = fix.code || '';
    const lower = code.toLowerCase();
    const sensitiveTables = ['profiles', 'verifications', 'messages', 'notifications', 'topup_requests'];
    const hasUsing = lower.includes('using (true)') || lower.includes('using(true)');
    if (hasUsing) {
      const mentionsTable = sensitiveTables.some(t => lower.includes(t));
      if (mentionsTable) {
        return {
          pass: false,
          reason: 'REJECTED: This policy uses USING (true) on a sensitive table, which would expose all rows to the target role. Scope the policy to auth.uid() or a role check.',
        };
      }
    }
    return { pass: true };
  },

  // Rule 7: INSERT INTO storage.buckets must not make buckets public
  (fix) => {
    const code = (fix.code || '').toLowerCase();
    if (code.includes('storage.buckets') && code.includes('public, true')) {
      return {
        pass: false,
        reason: 'REJECTED: This fix creates a PUBLIC storage bucket for verification photos. Verification photos (ID docs, selfies) must NEVER be in a public bucket. Use a private bucket with signed URLs.',
      };
    }
    return { pass: true };
  },

  // Rule 8: JS fixes to messages.js must not change conversation ID format without migration
  (fix) => {
    if ((fix.file || '').includes('messages.js') && (fix.code || '').includes('_makeConvId')) {
      return {
        pass: false,
        reason: 'REJECTED: Changing the conversation ID format (BUG 6 fix) is a breaking change that orphans all existing conversations. This requires: (1) a DB migration to update existing conv IDs, (2) coordination with all active users, (3) a fallback read path for old IDs. Escalate to lead engineer.',
      };
    }
    return { pass: true };
  },
];

// ── Known safe fix approvals ──────────────────────────────────────────────────
// These are pre-reviewed and explicitly approved with specific conditions.
const PRE_APPROVED = {
  'FIX-001': {
    preApproved: true,
    conditions:  ['Verify admin accounts are trusted before applying', 'Test in staging: sign in as admin, check listings tab shows pending items'],
    integrityImpact: 'Additive only — no existing data modified. New policy evaluated alongside existing policies.',
  },
  'FIX-002': {
    preApproved: true,
    conditions:  ['Use DROP POLICY IF EXISTS before CREATE POLICY to avoid duplicate policy error', 'Verify only admin-role users can list profiles in staging'],
    integrityImpact: 'Additive only. User self-read policy must remain in place.',
  },
  'FIX-003': {
    preApproved: true,
    conditions:  ['New table — no existing data risk', 'After creation, contact users with verification_pending=true and ask them to re-submit (their photos were not saved)'],
    integrityImpact: 'Creates new table with FK reference to profiles. FK constraint with ON DELETE CASCADE ensures cleanup.',
  },
  'FIX-008': {
    preApproved: true,
    conditions:  ['Must rebuild bundle.js after editing auth.js', 'Test wallet display shows correct balance after login', 'Test on a user with wallet_usd > 0 in DB'],
    integrityImpact: 'Pure frontend alias — no DB change. Additive.',
  },
  'FIX-009': {
    preApproved: true,
    conditions:  ['Must rebuild bundle.js after editing', 'Test: log in as user A, send a message, log out as user A, log in as user B — user B should NOT receive A\'s messages'],
    integrityImpact: 'No DB change. Improves cleanup on logout.',
  },
};

async function run(config, fixesResult) {
  logger.agent('AGENT 8 — Approval Gate');
  const decisions = [];

  const fixes = fixesResult && fixesResult.fixes ? fixesResult.fixes : [];
  if (fixes.length === 0) {
    logger.info('No fixes to evaluate');
    return { agent: 'ApprovalGate', status: 'pass', decisions: [], summary: { approved: 0, rejected: 0, needsRevision: 0 } };
  }

  logger.section(`Evaluating ${fixes.length} fix(es)`);

  for (const fix of fixes) {
    logger.info(`\n  Evaluating ${fix.id}: ${fix.description}`);

    const failedRules = [];
    const revisionRules = [];
    let preApprovalInfo = null;

    // Check pre-approved list first
    if (PRE_APPROVED[fix.id]) {
      preApprovalInfo = PRE_APPROVED[fix.id];
    }

    // Run all safety rules
    for (const rule of SAFETY_RULES) {
      const result = rule(fix);
      if (!result.pass && result.pass !== null) {
        failedRules.push(result.reason);
      } else if (result.pass === null) {
        revisionRules.push(result.reason);
      }
    }

    let decision;
    let reasoning;
    let sideEffects = [];
    let integrityImpact = preApprovalInfo ? preApprovalInfo.integrityImpact : '';

    if (failedRules.length > 0) {
      decision  = 'REJECTED';
      reasoning = failedRules[0];
      logger.decision(fix.id, 'REJECTED');
      logger.fail(`  ${failedRules[0]}`);
    } else if (revisionRules.length > 0 && !preApprovalInfo) {
      decision  = 'NEEDS_REVISION';
      reasoning = revisionRules.join(' | ');
      sideEffects = revisionRules;
      logger.decision(fix.id, 'NEEDS_REVISION');
      logger.warn(`  ${revisionRules[0]}`);
    } else {
      decision = 'APPROVED';
      if (preApprovalInfo) {
        reasoning = `Pre-reviewed and approved. Conditions: ${(preApprovalInfo.conditions || []).join('; ')}`;
        sideEffects = preApprovalInfo.conditions || [];
      } else {
        reasoning = `All safety rules passed. Safety level: ${fix.safetyLevel}. Apply in staging first, then production.`;
        sideEffects = fix.risks || [];
      }
      logger.decision(fix.id, 'APPROVED');
      logger.pass(`  ${reasoning.slice(0, 100)}`);
    }

    // Additional side-effect analysis
    const additionalSideEffects = analyzeAdditionalSideEffects(fix);
    sideEffects = [...new Set([...sideEffects, ...additionalSideEffects])];

    decisions.push({
      fixId:           fix.id,
      issueId:         fix.issueId,
      fixDescription:  fix.description,
      decision,
      reasoning,
      sideEffects,
      integrityImpact,
      applyStagingFirst: decision === 'APPROVED',
      applyInstructions: fix.apply || null,
      evaluatedAt:     new Date().toISOString(),
    });
  }

  logger.divider();
  const approved       = decisions.filter(d => d.decision === 'APPROVED').length;
  const rejected       = decisions.filter(d => d.decision === 'REJECTED').length;
  const needsRevision  = decisions.filter(d => d.decision === 'NEEDS_REVISION').length;

  logger.info(`Approval Gate Results:`);
  logger.pass(`  APPROVED:       ${approved}`);
  if (needsRevision) logger.warn(`  NEEDS_REVISION: ${needsRevision}`);
  if (rejected)      logger.fail(`  REJECTED:       ${rejected}`);

  if (approved > 0) {
    logger.info('\n  Approved fixes — apply in THIS ORDER (dependencies first):');
    const approvedFixes = decisions.filter(d => d.decision === 'APPROVED');
    // Order: SQL schema first, then JS
    const sqlFirst = [...approvedFixes].sort((a, b) => {
      const fa = fixes.find(f => f.id === a.fixId);
      const fb = fixes.find(f => f.id === b.fixId);
      if (!fa || !fb) return 0;
      if (fa.type === 'sql' && fb.type !== 'sql') return -1;
      if (fa.type !== 'sql' && fb.type === 'sql') return  1;
      return 0;
    });
    sqlFirst.forEach((d, i) => {
      logger.info(`  ${i + 1}. ${d.fixId} — ${d.fixDescription}`);
      if (d.applyInstructions) logger.info(`     HOW: ${d.applyInstructions}`);
    });
  }

  return {
    agent:   'ApprovalGate',
    status:  rejected > 0 ? 'warn' : 'pass',
    decisions,
    summary: { approved, rejected, needsRevision },
  };
}

function analyzeAdditionalSideEffects(fix) {
  const effects = [];
  const code    = fix.code || '';
  const lower   = code.toLowerCase();

  if (lower.includes('create policy') && lower.includes('listings')) {
    effects.push('Admin can now see non-active listings in Supabase dashboard. Adjust admin UI to filter by status if needed.');
  }
  if ((fix.file || '').includes('verify.js')) {
    effects.push('After applying: existing pending verifications in the verifications table (if any) will be readable. Existing base64 in profiles.selfie and profiles.idDocs should be cleaned up separately.');
  }
  if ((fix.file || '').includes('app.js') && (fix.fn || '').includes('fetchListings')) {
    effects.push('Pagination adds API calls. Monitor Supabase request count for rate limiting.');
    effects.push('H.state.listings array can grow beyond 200. Monitor localStorage size.');
  }
  if (lower.includes('alter column') && lower.includes('created_at')) {
    effects.push('All existing notification timestamps will be converted. Verify UI renders timestamps correctly after migration.');
    effects.push('Realtime subscriptions use the same channel — no change needed there.');
  }

  return effects;
}

if (require.main === module) {
  let config;
  try { config = require('../config'); } catch { config = require('../config.example'); }
  run(config, { fixes: [] }).then(r => {
    console.log(`\nApproval gate: ${r.summary.approved} approved, ${r.summary.rejected} rejected, ${r.summary.needsRevision} needs revision`);
  }).catch(e => { console.error(e.message); process.exit(1); });
}

module.exports = { run };
